# Potion Brewery
import random

class Ingredient:
    def __init__(self, name, potency):
        self.name = name
        self.potency = potency
        self.toxic = False

class Recipe:
    def __init__(self, name):
        self.name = name
        self.ingredients = []
        self.brew_time = 0

    def add(self, ingredient, qty):
        self.ingredients.append(
            (ingredient, qty))
        self.brew_time += qty

    def potency(self):
        total = sum(
            i.potency * q
            for i, q in self.ingredients
        )
        return total

class Brewery:
    def __init__(self):
        self.recipes = {}
        self.stock = []

    def register(self, recipe):
        self.recipes[recipe.name] = recipe

    def brew(self, name):
        recipe = self.recipes[name]
        potion = recipe.potency()
        self.stock.append(potion)
        return potion

